unit lipdecide;

{
  Launch Interceptor Program — Knight & Leveson (1986)
  Implementation of DECIDE and REALCOMPARE for the LIP specification.
  Uses global variables declared in the companion unit `globals`.
}

interface

uses globals;

function  REALCOMPARE(A, B : real) : COMPTYPE;
procedure DECIDE;

implementation

uses Math;

{ --------------------------------------------------------------------------
  REALCOMPARE
  Compares two real numbers to six significant digits.
  Returns LT, EQ, or GT.
  Strategy: scale both values by the magnitude of the larger, then compare
  with a tolerance of 0.5e-6 (i.e. half a unit in the sixth digit).
  -------------------------------------------------------------------------- }
function REALCOMPARE(A, B : real) : COMPTYPE;
const
  SIX_DIGITS = 1.0e-6;
var
  Scale, Diff : real;
begin
  { Determine scale from the larger absolute value }
  if Abs(A) > Abs(B) then
    Scale := Abs(A)
  else
    Scale := Abs(B);

  { If both are essentially zero, treat as equal }
  if Scale = 0.0 then
  begin
    REALCOMPARE := EQ;
    Exit;
  end;

  Diff := (A - B) / Scale;

  if Diff < -SIX_DIGITS then
    REALCOMPARE := LT
  else if Diff > SIX_DIGITS then
    REALCOMPARE := GT
  else
    REALCOMPARE := EQ;
end;

{ --------------------------------------------------------------------------
  Helper: Euclidean distance squared between two points
  -------------------------------------------------------------------------- }
function DistSq(X1, Y1, X2, Y2 : real) : real;
begin
  DistSq := (X2 - X1) * (X2 - X1) + (Y2 - Y1) * (Y2 - Y1);
end;

{ --------------------------------------------------------------------------
  Helper: Euclidean distance between two points
  -------------------------------------------------------------------------- }
function Dist(X1, Y1, X2, Y2 : real) : real;
begin
  Dist := Sqrt(DistSq(X1, Y1, X2, Y2));
end;

{ --------------------------------------------------------------------------
  Helper: Circumradius of the triangle formed by three points.
  Returns 0.0 when the three points are collinear (the circumradius is
  infinite, but for the LIC checks we only need to know it is > RADIUS,
  so returning a very large sentinel is correct — however, collinear points
  *can* be covered by a line segment treated as a degenerate circle of
  radius = half the longest side.  The spec says "contained within OR ON a
  circle of radius R", so for collinear points the minimum enclosing circle
  has radius = half the longest chord.  We therefore return that value when
  the triangle area is zero.
  -------------------------------------------------------------------------- }
function MinEnclosingRadius(X1, Y1, X2, Y2, X3, Y3 : real) : real;
var
  A, B, C  : real;   { side lengths }
  Area2    : real;   { twice the absolute area }
  R        : real;
  MaxSide  : real;   { longest side, used for collinear case }
begin
  A := Dist(X2, Y2, X3, Y3);
  B := Dist(X1, Y1, X3, Y3);
  C := Dist(X1, Y1, X2, Y2);

  { Twice the absolute area via cross product }
  Area2 := Abs((X2 - X1) * (Y3 - Y1) - (X3 - X1) * (Y2 - Y1));

  if Area2 = 0.0 then
  begin
    { Collinear: minimum enclosing circle = half the longest side }
    MaxSide := A;
    if B > MaxSide then MaxSide := B;
    if C > MaxSide then MaxSide := C;
    MinEnclosingRadius := MaxSide / 2.0;
  end
  else
  begin
    { Standard circumradius formula R = abc / (2 * area) = abc / Area2.
      The circumcircle passes through all three vertices and is the minimum
      enclosing circle for any non-degenerate triangle. }
    R := (A * B * C) / Area2;
    MinEnclosingRadius := R;
  end;
end;

{ --------------------------------------------------------------------------
  Helper: Twice the signed area of the triangle (X1,Y1),(X2,Y2),(X3,Y3).
  The actual area is |result| / 2.
  -------------------------------------------------------------------------- }
function TriangleArea2(X1, Y1, X2, Y2, X3, Y3 : real) : real;
begin
  TriangleArea2 := Abs((X2 - X1) * (Y3 - Y1) - (X3 - X1) * (Y2 - Y1));
end;

{ --------------------------------------------------------------------------
  Helper: Determine which quadrant (1..4) a point belongs to,
  applying the priority rule from the spec.
  -------------------------------------------------------------------------- }
function Quadrant(Xp, Yp : real) : integer;
begin
  { Priority: I first (includes positive axes and origin),
    then II (x<=0, y>=0 except already covered),
    then III (x<=0, y<0),
    then IV  (x>0,  y<0) }
  if (REALCOMPARE(Xp, 0.0) <> LT) and (REALCOMPARE(Yp, 0.0) <> LT) then
    Quadrant := 1         { x >= 0, y >= 0  =>  I  }
  else if (REALCOMPARE(Xp, 0.0) = LT) and (REALCOMPARE(Yp, 0.0) <> LT) then
    Quadrant := 2         { x <  0, y >= 0  =>  II }
  else if (REALCOMPARE(Xp, 0.0) = LT) and (REALCOMPARE(Yp, 0.0) = LT) then
    Quadrant := 3         { x <  0, y <  0  =>  III }
  else
    Quadrant := 4;        { x >= 0, y <  0  =>  IV  }
end;

{ --------------------------------------------------------------------------
  Helper: distance from point (PX,PY) to the line through (X1,Y1)-(X2,Y2).
  When the two line endpoints coincide, returns the distance from the
  coincident point to (PX,PY).
  -------------------------------------------------------------------------- }
function DistPointToLine(PX, PY, X1, Y1, X2, Y2 : real) : real;
var
  DX, DY, Len, Cross : real;
begin
  DX := X2 - X1;
  DY := Y2 - Y1;
  Len := Sqrt(DX * DX + DY * DY);
  if REALCOMPARE(Len, 0.0) = EQ then
    { Degenerate: endpoints coincide, return distance to that point }
    DistPointToLine := Dist(PX, PY, X1, Y1)
  else
  begin
    Cross := Abs((PX - X1) * DY - (PY - Y1) * DX);
    DistPointToLine := Cross / Len;
  end;
end;

{ ==========================================================================
  LIC EVALUATORS — each returns true when the condition is met
  ========================================================================== }

{ LIC 1: two consecutive points > LENGTH1 apart }
function LIC1 : boolean;
var
  i   : integer;
  D   : real;
begin
  LIC1 := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    D := Dist(X[i], Y[i], X[i+1], Y[i+1]);
    if REALCOMPARE(D, PARAMETERS.LENGTH1) = GT then
    begin
      LIC1 := true;
      Exit;
    end;
  end;
end;

{ LIC 2: three consecutive points that cannot all fit in a circle of RADIUS1 }
function LIC2 : boolean;
var
  i : integer;
  R : real;
begin
  LIC2 := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    R := MinEnclosingRadius(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2]);
    if REALCOMPARE(R, PARAMETERS.RADIUS1) = GT then
    begin
      LIC2 := true;
      Exit;
    end;
  end;
end;

{ LIC 3: three consecutive points with angle < PI-EPSILON or > PI+EPSILON }
function LIC3 : boolean;
var
  i              : integer;
  VX1, VY1       : real;   { vector from vertex to first point  }
  VX2, VY2       : real;   { vector from vertex to third point  }
  Len1, Len2     : real;
  CosA, Angle    : real;
begin
  LIC3 := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    { Vertex is point i+1 }
    VX1 := X[i]   - X[i+1];   VY1 := Y[i]   - Y[i+1];
    VX2 := X[i+2] - X[i+1];   VY2 := Y[i+2] - Y[i+1];
    Len1 := Sqrt(VX1*VX1 + VY1*VY1);
    Len2 := Sqrt(VX2*VX2 + VY2*VY2);

    { If either endpoint coincides with vertex, angle is undefined }
    if (REALCOMPARE(Len1, 0.0) = EQ) or (REALCOMPARE(Len2, 0.0) = EQ) then
      Continue;

    CosA := (VX1*VX2 + VY1*VY2) / (Len1 * Len2);
    { Clamp to [-1, 1] for numerical safety }
    if CosA > 1.0  then CosA :=  1.0;
    if CosA < -1.0 then CosA := -1.0;
    Angle := ArcCos(CosA);

    if (REALCOMPARE(Angle, PI - PARAMETERS.EPSILON) = LT) or
       (REALCOMPARE(Angle, PI + PARAMETERS.EPSILON) = GT) then
    begin
      LIC3 := true;
      Exit;
    end;
  end;
end;

{ LIC 4: three consecutive points forming a triangle with area > AREA1 }
function LIC4 : boolean;
var
  i    : integer;
  Area : real;
begin
  LIC4 := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    Area := TriangleArea2(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2]) / 2.0;
    if REALCOMPARE(Area, PARAMETERS.AREA1) = GT then
    begin
      LIC4 := true;
      Exit;
    end;
  end;
end;

{ LIC 5: Q_PTS consecutive points in more than QUADS quadrants }
function LIC5 : boolean;
var
  i, j, q  : integer;
  InQuad    : array[1..4] of boolean;
  Count     : integer;
begin
  LIC5 := false;
  for i := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
  begin
    InQuad[1] := false; InQuad[2] := false;
    InQuad[3] := false; InQuad[4] := false;
    for j := i to i + PARAMETERS.Q_PTS - 1 do
    begin
      q := Quadrant(X[j], Y[j]);
      InQuad[q] := true;
    end;
    Count := 0;
    for q := 1 to 4 do
      if InQuad[q] then Inc(Count);
    if Count > PARAMETERS.QUADS then
    begin
      LIC5 := true;
      Exit;
    end;
  end;
end;

{ LIC 6: two consecutive points (X[j], Y[j]) with X[j] - X[j-1] < 0 }
function LIC6 : boolean;
var
  i : integer;
begin
  LIC6 := false;
  for i := 2 to NUMPOINTS do
  begin
    if REALCOMPARE(X[i] - X[i-1], 0.0) = LT then
    begin
      LIC6 := true;
      Exit;
    end;
  end;
end;

{ LIC 7: N_PTS consecutive points with one point > DIST from the line
         joining the first and last of those N_PTS points.
         Not met when NUMPOINTS < 3. }
function LIC7 : boolean;
var
  i, k      : integer;
  iFirst, iLast : integer;
  D         : real;
begin
  LIC7 := false;
  if NUMPOINTS < 3 then Exit;

  for i := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
  begin
    iFirst := i;
    iLast  := i + PARAMETERS.N_PTS - 1;

    { Check each interior point (and all points when endpoints coincide) }
    for k := iFirst + 1 to iLast - 1 do
    begin
      D := DistPointToLine(X[k], Y[k],
                           X[iFirst], Y[iFirst],
                           X[iLast],  Y[iLast]);
      if REALCOMPARE(D, PARAMETERS.DIST) = GT then
      begin
        LIC7 := true;
        Exit;
      end;
    end;
  end;
end;

{ LIC 8: two points separated by K_PTS intervening points, distance > LENGTH1.
         Not met when NUMPOINTS < 3. }
function LIC8 : boolean;
var
  i  : integer;
  j  : integer;
  D  : real;
begin
  LIC8 := false;
  if NUMPOINTS < 3 then Exit;

  { i is first point index; j = i + K_PTS + 1 is second point index }
  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    j := i + PARAMETERS.K_PTS + 1;
    D := Dist(X[i], Y[i], X[j], Y[j]);
    if REALCOMPARE(D, PARAMETERS.LENGTH1) = GT then
    begin
      LIC8 := true;
      Exit;
    end;
  end;
end;

{ LIC 9: three points separated by A_PTS and B_PTS, cannot fit in circle of
         RADIUS1.  Not met when NUMPOINTS < 5. }
function LIC9 : boolean;
var
  i, j, k : integer;
  R        : real;
begin
  LIC9 := false;
  if NUMPOINTS < 5 then Exit;

  { i, j = i+A_PTS+1, k = j+B_PTS+1 }
  for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    j := i + PARAMETERS.A_PTS + 1;
    k := j + PARAMETERS.B_PTS + 1;
    R := MinEnclosingRadius(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
    if REALCOMPARE(R, PARAMETERS.RADIUS1) = GT then
    begin
      LIC9 := true;
      Exit;
    end;
  end;
end;

{ LIC 10: three points separated by C_PTS and D_PTS, forming an angle outside
          [PI-EPSILON, PI+EPSILON].  Not met when NUMPOINTS < 5. }
function LIC10 : boolean;
var
  i, j, k        : integer;
  VX1, VY1       : real;
  VX2, VY2       : real;
  Len1, Len2     : real;
  CosA, Angle    : real;
begin
  LIC10 := false;
  if NUMPOINTS < 5 then Exit;

  for i := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 2 do
  begin
    j := i + PARAMETERS.C_PTS + 1;
    k := j + PARAMETERS.D_PTS + 1;

    { Vertex is j }
    VX1 := X[i] - X[j];   VY1 := Y[i] - Y[j];
    VX2 := X[k] - X[j];   VY2 := Y[k] - Y[j];
    Len1 := Sqrt(VX1*VX1 + VY1*VY1);
    Len2 := Sqrt(VX2*VX2 + VY2*VY2);

    if (REALCOMPARE(Len1, 0.0) = EQ) or (REALCOMPARE(Len2, 0.0) = EQ) then
      Continue;

    CosA := (VX1*VX2 + VY1*VY2) / (Len1 * Len2);
    if CosA > 1.0  then CosA :=  1.0;
    if CosA < -1.0 then CosA := -1.0;
    Angle := ArcCos(CosA);

    if (REALCOMPARE(Angle, PI - PARAMETERS.EPSILON) = LT) or
       (REALCOMPARE(Angle, PI + PARAMETERS.EPSILON) = GT) then
    begin
      LIC10 := true;
      Exit;
    end;
  end;
end;

{ LIC 11: three points separated by E_PTS and F_PTS, triangle area > AREA1.
          Not met when NUMPOINTS < 5. }
function LIC11 : boolean;
var
  i, j, k : integer;
  Area     : real;
begin
  LIC11 := false;
  if NUMPOINTS < 5 then Exit;

  for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    j := i + PARAMETERS.E_PTS + 1;
    k := j + PARAMETERS.F_PTS + 1;
    Area := TriangleArea2(X[i], Y[i], X[j], Y[j], X[k], Y[k]) / 2.0;
    if REALCOMPARE(Area, PARAMETERS.AREA1) = GT then
    begin
      LIC11 := true;
      Exit;
    end;
  end;
end;

{ LIC 12: two points separated by G_PTS, X[j] - X[i] < 0.
          Not met when NUMPOINTS < 3. }
function LIC12 : boolean;
var
  i, j : integer;
begin
  LIC12 := false;
  if NUMPOINTS < 3 then Exit;

  for i := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
  begin
    j := i + PARAMETERS.G_PTS + 1;
    if REALCOMPARE(X[j] - X[i], 0.0) = LT then
    begin
      LIC12 := true;
      Exit;
    end;
  end;
end;

{ LIC 13: (a) two points separated by K_PTS with distance > LENGTH1, AND
           (b) two points separated by K_PTS with distance < LENGTH2.
           Not met when NUMPOINTS < 3. }
function LIC13 : boolean;
var
  i, j    : integer;
  D       : real;
  PartA   : boolean;
  PartB   : boolean;
begin
  LIC13 := false;
  if NUMPOINTS < 3 then Exit;

  PartA := false;
  PartB := false;

  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    j := i + PARAMETERS.K_PTS + 1;
    D := Dist(X[i], Y[i], X[j], Y[j]);
    if REALCOMPARE(D, PARAMETERS.LENGTH1) = GT then PartA := true;
    if REALCOMPARE(D, PARAMETERS.LENGTH2) = LT then PartB := true;
    if PartA and PartB then
    begin
      LIC13 := true;
      Exit;
    end;
  end;

  LIC13 := PartA and PartB;
end;

{ LIC 14: (a) three points separated by A_PTS, B_PTS cannot fit in RADIUS1, AND
           (b) three points separated by A_PTS, B_PTS can fit in RADIUS2.
           Not met when NUMPOINTS < 5. }
function LIC14 : boolean;
var
  i, j, k  : integer;
  R         : real;
  PartA     : boolean;
  PartB     : boolean;
begin
  LIC14 := false;
  if NUMPOINTS < 5 then Exit;

  PartA := false;
  PartB := false;

  for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    j := i + PARAMETERS.A_PTS + 1;
    k := j + PARAMETERS.B_PTS + 1;
    R := MinEnclosingRadius(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
    if REALCOMPARE(R, PARAMETERS.RADIUS1) = GT then PartA := true;
    if REALCOMPARE(R, PARAMETERS.RADIUS2) <> GT then PartB := true;
    if PartA and PartB then
    begin
      LIC14 := true;
      Exit;
    end;
  end;

  LIC14 := PartA and PartB;
end;

{ LIC 15: (a) three points separated by E_PTS, F_PTS with area > AREA1, AND
           (b) three points separated by E_PTS, F_PTS with area < AREA2.
           Not met when NUMPOINTS < 5. }
function LIC15 : boolean;
var
  i, j, k  : integer;
  Area      : real;
  PartA     : boolean;
  PartB     : boolean;
begin
  LIC15 := false;
  if NUMPOINTS < 5 then Exit;

  PartA := false;
  PartB := false;

  for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    j := i + PARAMETERS.E_PTS + 1;
    k := j + PARAMETERS.F_PTS + 1;
    Area := TriangleArea2(X[i], Y[i], X[j], Y[j], X[k], Y[k]) / 2.0;
    if REALCOMPARE(Area, PARAMETERS.AREA1) = GT then PartA := true;
    if REALCOMPARE(Area, PARAMETERS.AREA2) = LT then PartB := true;
    if PartA and PartB then
    begin
      LIC15 := true;
      Exit;
    end;
  end;

  LIC15 := PartA and PartB;
end;

{ ==========================================================================
  DECIDE
  Evaluates all 15 LICs, builds the CMV, PUM, FUV, and LAUNCH decision.
  ========================================================================== }
procedure DECIDE;
var
  i, j   : integer;
  AllTrue : boolean;
begin
  { --- Step 1: Evaluate each LIC and populate CMV --- }
  CMV[1]  := LIC1;
  CMV[2]  := LIC2;
  CMV[3]  := LIC3;
  CMV[4]  := LIC4;
  CMV[5]  := LIC5;
  CMV[6]  := LIC6;
  CMV[7]  := LIC7;
  CMV[8]  := LIC8;
  CMV[9]  := LIC9;
  CMV[10] := LIC10;
  CMV[11] := LIC11;
  CMV[12] := LIC12;
  CMV[13] := LIC13;
  CMV[14] := LIC14;
  CMV[15] := LIC15;

  { --- Step 2: Build the off-diagonal elements of the PUM --- }
  for i := 1 to 15 do
    for j := 1 to 15 do
    begin
      if i = j then
        Continue;  { diagonal elements are provided as input; leave untouched }

      case LCM[i, j] of
        NOTUSED : PUM[i, j] := true;
        ANDD    : PUM[i, j] := CMV[i] and CMV[j];
        ORR     : PUM[i, j] := CMV[i] or  CMV[j];
      end;
    end;

  { --- Step 3: Build the FUV --- }
  for i := 1 to 15 do
  begin
    if not PUM[i, i] then
    begin
      { Diagonal false => LIC should not hold back launch }
      FUV[i] := true;
    end
    else
    begin
      { All elements in row i must be true }
      AllTrue := true;
      for j := 1 to 15 do
        if not PUM[i, j] then
        begin
          AllTrue := false;
          Break;
        end;
      FUV[i] := AllTrue;
    end;
  end;

  { --- Step 4: LAUNCH is true iff every FUV entry is true --- }
  LAUNCH := true;
  for i := 1 to 15 do
    if not FUV[i] then
    begin
      LAUNCH := false;
      Break;
    end;
end;

end.
